void MRFSmoothCurve::BuildGraph()
{
	if (!!_pSmoothCurveDlg)
	{
		AddAnalyseNotificationCB(_pSmoothCurveDlg, _pSmoothCurveDlg->GetDiaOKNotification(), (CATCommandMethod)& MRFSmoothCurve::ActionOne, NULL);
		AddAnalyseNotificationCB(_pSmoothCurveDlg, _pSmoothCurveDlg->GetDiaCANCELNotification(), (CATCommandMethod)& MRFSmoothCurve::ActionClose, NULL);
		AddAnalyseNotificationCB(_pSmoothCurveDlg, _pSmoothCurveDlg->GetWindCloseNotification(), (CATCommandMethod)& MRFSmoothCurve::ActionClose, NULL);

		CATListOfCATString List3DElements;
		List3DElements.Append("CATI3DGeometricalElement");

		_p3DCurvePathElementAgent = new CATPathElementAgent("RefElementPathElementAgent");
		if (_p3DCurvePathElementAgent)
		{
			_p3DCurvePathElementAgent->SetOrderedTypeList(List3DElements);
			_p3DCurvePathElementAgent->SetBehavior(CATDlgEngWithPrevaluation | CATDlgEngRepeat | CATDlgEngWithPSO);

		}
		_p3DCurveDialogAgent = new CATDialogAgent("3DCurveDialogAgent");
		if (!!_p3DCurveDialogAgent && !!_p3DCurveSelector)
		{
			_p3DCurveDialogAgent->AcceptOnNotify(_p3DCurveSelector, _p3DCurveSelector->GetListSelectNotification());
		}
		CATDialogState * pInitialState = GetInitialState("InitialState");
		pInitialState->AddDialogAgent(_p3DCurveDialogAgent);
		pInitialState->AddDialogAgent(_p3DCurvePathElementAgent);

		AddTransition(pInitialState, pInitialState, IsOutputSetCondition(_p3DCurveDialogAgent), Action((ActionMethod)&MRFSmoothCurve::OnSelectorListSelected));
		AddTransition(pInitialState, pInitialState, IsOutputSetCondition(_p3DCurvePathElementAgent), Action((ActionMethod)&MRFSmoothCurve::OnObjectSelection));
	}

}

void MRFSmoothCurve::ActionOne(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	SmoothenCurve();
	RequestDelayedDestruction();
	return;
}

void MRFSmoothCurve::ActionClose(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	this->ExecuteUndoAtEnd();
	RequestDelayedDestruction();

	return;
}

